const cco_applicable_err_msg = 'Something went wrong! Please try after sometime.';
const cco_applicable_err_msg_span = '<span class="font-sm text-danger">'+ cco_applicable_err_msg +'</span>';

$(document).ready(function() {

    $(document).delegate('.circular-applicable-checkbox', 'change', function() {
        var checkbox = $(this);
        var data = { id : checkbox.data('circularid') };
        data.status = checkbox.is(':checked') ? 1 : 0;
        data.url = checkbox.data('url');

        var statusContainer = checkbox.closest('.circular-applicable-switch-class').find('.circular-applicable-switch-status');
        
        if(statusContainer.length > 0)
        {
            // remove all span
            statusContainer.find('span').remove();

            $.ajax({

                url: data.url,
                type: 'POST',
                data: data,

                beforeSend: function() {
                    $( statusContainer ).html('<span class="font-sm text-secondary">Please wait...</span>');
                },

                success: function(res) {

                    // remove span
                    statusContainer.find('span').remove();

                    try
                    {
                        res = JSON.parse(res);
                        var errClass = true;

                        if (res.status !== undefined) {

                            errClass = false;

                            if (res.status === 1)
                                checkbox.closest('.circular-applicable-switch-class').find('.form-check-label').text('Applicable').addClass('text-success').removeClass('text-danger');
                            else
                                checkbox.closest('.circular-applicable-switch-class').find('.form-check-label').text('Not Applicable').addClass('text-danger').removeClass('text-success');
                        }
                        
                        $( statusContainer ).html('<span class="font-sm '+ ( errClass ? 'text-danger' : 'text-success' ) +'">'+ res.msg +'</span>');

                        // remove success span after 5 sec
                        setTimeout(() => {
                            statusContainer.find('span').remove();
                        }, 5000);
                    }
                    catch (error) { $( statusContainer ).html(cco_applicable_err_msg_span); }

                },

                error: function(res) {
                    // remove span
                    statusContainer.find('span').remove();
                    
                    $( statusContainer ).html(cco_applicable_err_msg_span);
                }
            });
        }
        else
            alert(cco_applicable_err_msg);

        // Remove existing status message before new request
        // checkbox.closest('.applicable-switch-class').find('.applicable-switch-status span').remove();
    });

});